SELECT team_id, wins, losses
FROM team_stats
WHERE win_percentage = (SELECT MAX(win_percentage) FROM team_stats);

SELECT AVG(height) AS average_height
FROM players
WHERE team_id = 1;

SELECT
    (SELECT SUM(points_for) FROM team_stats WHERE team_id = 1) AS total_points,
    (SELECT AVG(height) FROM players WHERE team_id = 1) AS average_height;
